#include <stdio.h>
#include <string.h>

int len;

void cyclicShift(char str[])
{
	char temp = str[0];

	for(int i = 0; i < len; i++)
	{
		str[i] = str[i + 1];
	}

	str[len - 1] = temp;
}

int tot = 0;
char stack[51][51];

void isdistinct(char str[])
{
	for(int i = 0; i < tot; i++)
	{
		if(strcmp(str, stack[i]) == 0)
		{
			return;
		}
	}

	strcpy(stack[tot++], str);
}

int main(void)
{
	char str[51];
	scanf("%s", &str);

	len = strlen(str);

	for(int i = 0; i < len; i++)
	{
		isdistinct(str);
		cyclicShift(str);
	}

	printf("%d\n", tot);

	return 0;
}

